#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/wait.h>
#include <unistd.h>
#include <string.h>
#include <stdatomic.h>

typedef struct {
    atomic_int counter;
    atomic_int ready;
} AtomicShared;

int main(void) {
    int fd = shm_open("/kf_shm_atomic", O_CREAT | O_RDWR, 0644);
    ftruncate(fd, sizeof(AtomicShared));
    AtomicShared *as = (AtomicShared *)mmap(NULL, sizeof(AtomicShared),
        PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);

    atomic_store(&as->counter, 0);
    atomic_store(&as->ready, 0);

    for (int i = 0; i < 4; i++) {
        if (fork() == 0) {
            for (int j = 0; j < 1000; j++)
                atomic_fetch_add(&as->counter, 1);
            atomic_fetch_add(&as->ready, 1);
            _exit(0);
        }
    }

    while (atomic_load(&as->ready) < 4)
        usleep(1000);

    printf("Atomic counter: %d\n", atomic_load(&as->counter));

    munmap(as, sizeof(AtomicShared));
    shm_unlink("/kf_shm_atomic");
    return 0;
}

